const b   = $input.first().json.body || {};
const esc = v => (v || '').toString().replace(/'/g, "''");

const complaintNo = esc(b.complaintNo || b.complaintId || '').trim();
const remarks     = esc(b.remarks || '');
const newStatus   = esc(b.newStatus || '');
const newEdc      = esc(b.newEdc || '');
const uid         = parseInt(b.uid || 1);

if (!complaintNo) return [{ json: { error: 'complaintNo required' } }];

const sqlFind = `SELECT c.id FROM vmm_complaints c WHERE c.complaintno = '${complaintNo}' AND c.is_deleted = 'No' LIMIT 1`;

return [{ json: { sqlFind, complaintNo, remarks, newStatus, newEdc, uid } }];

const prev  = $('Prepare').first().json;
const row   = $input.first()?.json;

if (!row || !row.id) {
  return [{ json: { found: false, message: `Complaint ${prev.complaintNo} not found`, insertLog: 'SELECT 1', updateEdc: null } }];
}

const cid = row.id;
const esc = v => (v || '').toString().replace(/'/g, "''");

const statusToLog = prev.newStatus || 'Open';
const logRemarks  = prev.remarks || 'Update received';

const insertLog = `INSERT INTO vmm_complaintlogs (complaintid, remarks, status, uid, created, is_deleted) VALUES (${cid}, '${esc(logRemarks)}', '${esc(statusToLog)}', ${prev.uid}, NOW(), 'No')`;

const updateEdc = prev.newEdc
  ? `UPDATE vmm_vendorescalations SET closuredate = '${esc(prev.newEdc)}' WHERE id = (SELECT MAX(id) FROM vmm_vendorescalations WHERE complaintid = ${cid})`
  : null;

return [{ json: { found: true, cid, complaintNo: prev.complaintNo, insertLog, updateEdc, statusToLog } }];
